import React, { useState, useEffect, useCallback } from 'react';
import { useTranslation } from '../hooks/useTranslation';

const Services = () => {
  const { t } = useTranslation();
  const [activeSidebar, setActiveSidebar] = useState(null);

  const services = [
    {
      icon: "bi-code-slash",
      title_key: "service_1_title",
      description_key: "service_1_text",
      id: "fullstack"
    },
    {
      icon: "bi-palette",
      title_key: "service_3_title",
      description_key: "service_3_text",
      id: "uiux"
    },
    {
      icon: "bi-card-checklist",
      title_key: "service_4_title",
      description_key: "service_4_text",
      id: "software"
    },
    {
      icon: "bi-bar-chart-line",
      title_key: "service_6_title", 
      description_key: "service_6_text",
      id: "powerbi"
    }
  ];

  const handleOpenSidebar = (id) => {
    setActiveSidebar(id);
    document.body.style.overflow = 'hidden';
  };

  const handleCloseSidebar = useCallback(() => {
    setActiveSidebar(null);
    document.body.style.overflow = '';
  }, []);

  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'Escape' && activeSidebar) {
        handleCloseSidebar();
      }
    };

    document.addEventListener('keydown', handleKeyDown);
    return () => document.removeEventListener('keydown', handleKeyDown);
  }, [activeSidebar, handleCloseSidebar]);

  const sidebarContent = {
    fullstack: {
      title: "Desenvolvimento Full Stack",
      link: "https://matheusabib.github.io/Tela-de-links-Figma/",
      linkText: "Ver Projetos",
      frontend: ["HTML5", "CSS3", "SCSS", "JavaScript", "TypeScript", "React", "Angular"],
      backend: ["Java", "Spring Boot", "Node.js", "Express", "MySQL"],
      tools: ["Git", "GitHub", "VS Code", "Postman"],
      experience: "Atuo como Desenvolvedor de Software na Prefeitura de Mogi das Cruzes, desenvolvendo sistemas com Angular, TypeScript e Spring Boot seguindo a metodologia Scrum. Participo ativamente do levantamento de requisitos com clientes e entregas incrementais.",
      differentials: ["Código limpo e organizado", "Versionamento com Git", "Metodologias ágeis", "Testes e qualidade"],
      process: [
        { step: "01", title: "Análise de Requisitos", desc: "Levantamento detalhado das necessidades do cliente, definição de escopo e regras de negócio.", tags: ["Requisitos", "Escopo", "Documentação"] },
        { step: "02", title: "Arquitetura & Design", desc: "Definição da arquitetura da aplicação, escolha das tecnologias e modelagem do banco de dados.", tags: ["Arquitetura", "Modelagem", "UML"] },
        { step: "03", title: "Desenvolvimento", desc: "Codificação seguindo boas práticas, padrões de projeto e versionamento contínuo com Git.", tags: ["Clean Code", "Git", "Code Review"] },
        { step: "04", title: "Testes & Qualidade", desc: "Testes unitários, integração e validação para garantir a qualidade e confiabilidade do sistema.", tags: ["Testes", "QA", "Validação"] },
        { step: "05", title: "Entrega & Deploy", desc: "Deploy controlado, monitoramento e suporte contínuo após a entrega.", tags: ["Deploy", "Monitoramento", "Suporte"] }
      ]
    },
    uiux: {
      title: "UI/UX Design",
      link: "https://matheusabib.github.io/Tela-de-links-Figma/",
      linkText: "Ver Projetos",
      frontend: ["Figma", "Canva", "Adobe XD", "Sketch"],
      backend: ["UX Research", "Testes de Usabilidade", "Analytics"],
      tools: ["Miro", "Hotjar", "Google Analytics"],
      experience: "Criação de wireframes e protótipos interativos com foco em usabilidade e interfaces claras. Experiência em design systems, componentes reutilizáveis e validação com stakeholders.",
      differentials: ["Design centrado no usuário", "Prototipagem interativa", "Testes A/B", "Acessibilidade"],
      process: [
        { step: "01", title: "Imersão & Pesquisa", desc: "Análise do público-alvo, benchmarking e definição de personas para direcionar o design.", tags: ["Personas", "Benchmarking", "Pesquisa"] },
        { step: "02", title: "Wireframing", desc: "Criação de wireframes de baixa e alta fidelidade para definir arquitetura da informação e fluxos.", tags: ["Wireframes", "Arquitetura", "Fluxos"] },
        { step: "03", title: "Design Visual", desc: "Desenvolvimento da interface com paleta de cores, tipografia e componentes visuais consistentes.", tags: ["UI Design", "Sistema de Design", "Componentes"] },
        { step: "04", title: "Prototipagem", desc: "Criação de protótipos interativos para simular a experiência real do usuário.", tags: ["Protótipo", "Interatividade", "Figma"] },
        { step: "05", title: "Testes & Validação", desc: "Testes de usabilidade com usuários reais e iteração baseada no feedback.", tags: ["Testes de Usabilidade", "Feedback", "Iteração"] }
      ]
    },
    software: {
      title: "Engenharia de Software",
      link: null,
      linkText: null,
      frontend: ["Scrum", "Kanban", "XP", "SAFe"],
      backend: ["UML", "Documentação", "Arquitetura"],
      tools: ["Trello", "Jira", "Confluence", "Git"],
      experience: "Formação em Análise e Desenvolvimento de Sistemas (Fatec) e Engenharia de Software (UMC). Experiência prática com metodologias ágeis, levantamento de requisitos, gestão de backlog e controle de qualidade.",
      differentials: ["Gestão de projetos ágeis", "Documentação técnica", "Métricas e KPIs", "Melhoria contínua"],
      process: [
        { step: "01", title: "Levantamento", desc: "Coleta de requisitos funcionais e não funcionais com stakeholders.", tags: ["Requisitos", "Stakeholders", "Entrevistas"] },
        { step: "02", title: "Planejamento", desc: "Definição do backlog, sprints e alocação de recursos.", tags: ["Backlog", "Sprints", "Planejamento"] },
        { step: "03", title: "Desenvolvimento", desc: "Execução das sprints com revisões diárias e adaptação contínua.", tags: ["Scrum", "Daily", "Review"] },
        { step: "04", title: "Qualidade", desc: "Testes automatizados, revisões de código e garantia de qualidade.", tags: ["Testes", "Code Review", "QA"] },
        { step: "05", title: "Entrega", desc: "Deploy, retrospectiva e feedback para próximas iterações.", tags: ["Deploy", "Retrospectiva", "Feedback"] }
      ]
    },
    powerbi: {
      title: "Power BI & Análise de Dados",
      link: "https://matheusabib.github.io/Tela-de-Links-PowerBI/",
      linkText: "Ver Dashboards",
      frontend: ["Power BI", "Power Query", "DAX"],
      backend: ["Oracle", "SQL Server", "MySQL", "Excel"],
      tools: ["SSMS", "Azure", "SharePoint"],
      experience: "Curso Microsoft Power BI Para Business Intelligence e Data Science. Criação de dashboards interativos, modelagem de dados relacionais e geração de insights estratégicos para tomada de decisão.",
      differentials: ["ETL com Power Query", "Medidas DAX complexas", "Storytelling com dados", "Automação de relatórios"],
      process: [
        { step: "01", title: "Coleta de Dados", desc: "Conexão com múltiplas fontes de dados (Oracle, SQL Server, Excel, APIs).", tags: ["ETL", "Power Query", "Fontes de dados"] },
        { step: "02", title: "Limpeza & Transformação", desc: "Tratamento de dados inconsistentes, remoção de duplicatas e padronização.", tags: ["Limpeza", "Transformação", "Tratamento"] },
        { step: "03", title: "Modelagem", desc: "Criação de relacionamentos entre tabelas e construção do modelo dimensional.", tags: ["Modelagem", "Relacionamentos", "Star Schema"] },
        { step: "04", title: "DAX & Medidas", desc: "Criação de medidas e cálculos personalizados para análises avançadas.", tags: ["DAX", "Medidas", "Cálculos"] },
        { step: "05", title: "Dashboard & Insights", desc: "Desenvolvimento de dashboards interativos e apresentação de insights acionáveis.", tags: ["Dashboard", "Insights", "Storytelling"] }
      ]
    }
  };

  const activeContent = activeSidebar ? sidebarContent[activeSidebar] : null;

  return (
    <>
      <section id="services" className="services section">
        <div className="section-glow"></div>
        <div className="section-waves"></div>
        <div className="section-orbs">
          <div className="orb orb-1"></div>
          <div className="orb orb-2"></div>
          <div className="orb orb-3"></div>
        </div>

        <div className="container">
          <div className="section-title" data-aos="fade-up">
            <h2 data-translate="services_title">{t('services_title')}</h2>
          </div>
        </div>

        <div className="container" data-aos="fade-up" data-aos-delay="100">
          <div className="services-grid">
            {services.map((service, index) => (
              <div 
                key={index} 
                className="service-item"
                data-aos="fade-up"
                data-aos-delay={150 + (index * 100)}
              >
                <div className="service-icon">
                  <i className={`bi ${service.icon}`}></i>
                </div>
                <div className="service-content">
                  <h3 data-translate={service.title_key}>{t(service.title_key)}</h3>
                  <p data-translate={service.description_key}>{t(service.description_key)}</p>
                  <a 
                    href="#"
                    className="service-link"
                    onClick={(e) => {
                      e.preventDefault();
                      handleOpenSidebar(service.id);
                    }}
                  >
                    <span data-translate="see_button">{t('see_button')}</span>
                    <i className="bi bi-arrow-right"></i>
                  </a>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      <div className={`sidebar-overlay ${activeSidebar ? 'active' : ''}`} onClick={handleCloseSidebar}></div>
      
      <div className={`service-sidebar ${activeSidebar ? 'active' : ''}`}>
        <div className="sidebar-header">
          <div className="sidebar-header-content">
            <h2>{activeContent?.title}</h2>
            {activeContent?.link && (
              <a href={activeContent.link} target="_blank" rel="noopener noreferrer">
                <i className="bi bi-eye me-2"></i>
                {activeContent.linkText}
              </a>
            )}
          </div>
          <button className="sidebar-close" onClick={handleCloseSidebar}>
            <i className="bi bi-x-lg"></i>
          </button>
        </div>
        
        <div className="sidebar-body">
          <div className="sidebar-grid">
            <div className="sidebar-column">
              <div className="sidebar-section">
                <div className="section-header">
                  <div className="section-icon frontend-icon">
                    <i className="bi bi-window"></i>
                  </div>
                  <h3>Front-end</h3>
                </div>
                <div className="tech-stack-list">
                  {activeContent?.frontend.map((tech, idx) => (
                    <span key={idx} className="stack-tag">{tech}</span>
                  ))}
                </div>
              </div>
              
              <div className="sidebar-section">
                <div className="section-header">
                  <div className="section-icon backend-icon">
                    <i className="bi bi-server"></i>
                  </div>
                  <h3>Back-end</h3>
                </div>
                <div className="tech-stack-list">
                  {activeContent?.backend.map((tech, idx) => (
                    <span key={idx} className="stack-tag">{tech}</span>
                  ))}
                </div>
              </div>

              <div className="sidebar-section">
                <div className="section-header">
                  <div className="section-icon tools-icon">
                    <i className="bi bi-tools"></i>
                  </div>
                  <h3>Ferramentas</h3>
                </div>
                <div className="tech-stack-list">
                  {activeContent?.tools.map((tech, idx) => (
                    <span key={idx} className="stack-tag">{tech}</span>
                  ))}
                </div>
              </div>
            </div>
            
            <div className="sidebar-column">
              <div className="sidebar-section">
                <div className="section-header">
                  <div className="section-icon experience-icon">
                    <i className="bi bi-briefcase"></i>
                  </div>
                  <h3>Experiência Prática</h3>
                </div>
                <div className="Descricao-modal">
                  <p>{activeContent?.experience}</p>
                </div>
              </div>

              <div className="sidebar-section">
                <div className="section-header">
                  <div className="section-icon differential-icon">
                    <i className="bi bi-star"></i>
                  </div>
                  <h3>Diferenciais</h3>
                </div>
                <div className="differentials-list">
                  {activeContent?.differentials.map((diff, idx) => (
                    <span key={idx} className="differential-tag">
                      <i className="bi bi-check-circle-fill"></i>
                      {diff}
                    </span>
                  ))}
                </div>
              </div>

              <div className="sidebar-section process-section">
                <div className="section-header">
                  <div className="section-icon process-icon">
                    <i className="bi bi-diagram-3"></i>
                  </div>
                  <h3>Processo de Trabalho</h3>
                </div>
                
                <div className="process-timeline">
                  {activeContent?.process.map((item, idx) => (
                    <div key={idx} className="process-step">
                      <div className="step-indicator">
                        <span className="step-number-passo">{item.step}</span>
                      </div>
                      <div className="step-content-passo">
                        <div className="step-header">
                          <h4>{item.title}</h4>
                        </div>
                        <p>{item.desc}</p>
                        <div className="step-tags">
                          {item.tags.map((tag, tagIdx) => (
                            <span key={tagIdx} className="step-tag">{tag}</span>
                          ))}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </>
  );
};

export default Services;
